
'use client';

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { MoreHorizontal, ArrowRight, Bot, Filter } from "lucide-react";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuLabel, DropdownMenuTrigger, DropdownMenuCheckboxItem } from "@/components/ui/dropdown-menu";
import Link from "next/link";
import { useToast } from "@/hooks/use-toast";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

const initialIncidents = [
  { id: 'I501', route: 'R002', driver: 'Jane Smith', date: '2024-05-20', report: 'Heavy traffic near Main St caused a 15-minute delay.', severity: 'Low', status: 'Closed' },
  { id: 'I502', route: 'R004', driver: 'Mary Poppins', date: '2024-05-18', report: 'Minor fender bender at a stop sign. No injuries, police report filed.', severity: 'Medium', status: 'Under Review' },
  { id: 'I503', route: 'R001', driver: 'John Doe', date: '2024-05-15', report: 'Parent reported the bus running 5 minutes late consistently.', severity: 'Low', status: 'Closed' },
  { id: 'I504', route: 'R002', driver: 'Jane Smith', date: '2024-05-12', report: 'A student felt sick on the bus. Protocol was followed.', severity: 'Low', status: 'Closed' },
  { id: 'I505', route: 'R007', driver: 'N/A', date: '2024-05-10', report: 'Student reported driver seemed distracted, possibly on their phone.', severity: 'High', status: 'Investigation Open' },
];

type Incident = typeof initialIncidents[0];
const incidentStatuses = ['Closed', 'Under Review', 'Investigation Open', 'Escalated'];

export default function SafetyReportsPage() {
    const { toast } = useToast();
    const [incidents, setIncidents] = useState(initialIncidents);
    const [filterSeverity, setFilterSeverity] = useState({ low: true, medium: true, high: true });
    const [isStatusDialogOpen, setIsStatusDialogOpen] = useState(false);
    const [selectedIncident, setSelectedIncident] = useState<Incident | null>(null);


    const handleFilterChange = (severity: 'low' | 'medium' | 'high') => {
        setFilterSeverity(prev => ({...prev, [severity]: !prev[severity]}));
    };

    const filteredIncidents = incidents.filter(incident => {
        if (filterSeverity.low && incident.severity === 'Low') return true;
        if (filterSeverity.medium && incident.severity === 'Medium') return true;
        if (filterSeverity.high && incident.severity === 'High') return true;
        return false;
    });

    const openStatusDialog = (incident: Incident) => {
        setSelectedIncident(incident);
        setIsStatusDialogOpen(true);
    };

    const handleUpdateStatus = (event: React.FormEvent<HTMLFormElement>) => {
        event.preventDefault();
        if (!selectedIncident) return;
        
        const formData = new FormData(event.currentTarget);
        const newStatus = formData.get('status') as string;

        setIncidents(incidents.map(i => i.id === selectedIncident.id ? { ...i, status: newStatus } : i));
        setIsStatusDialogOpen(false);
        setSelectedIncident(null);
        toast({
            title: "Incident Status Updated",
            description: `Incident ${selectedIncident.id} status has been updated to ${newStatus}.`,
        });
    };
    
    const handleActionToast = (action: string, incidentId: string) => {
        toast({
            title: `Action: ${action}`,
            description: `Action "${action}" triggered for incident ${incidentId}.`,
        });
    };

  return (
    <div className="space-y-8">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold font-headline">Safety Incident Reports</h1>
          <p className="text-muted-foreground">Review, manage, and resolve all reported incidents.</p>
        </div>
        <Button asChild variant="outline">
          <Link href="/dashboard/admin/safety-analysis">
            <Bot className="mr-2 h-4 w-4" /> AI Analysis <ArrowRight className="ml-2 h-4 w-4" />
          </Link>
        </Button>
      </div>

      <Card>
        <CardHeader className="flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
            <div>
                <CardTitle>All Incidents</CardTitle>
                <CardDescription>A log of all safety-related reports.</CardDescription>
            </div>
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline">
                  <Filter className="mr-2 h-4 w-4" /> Filter
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                <DropdownMenuLabel>Filter by Severity</DropdownMenuLabel>
                <DropdownMenuCheckboxItem checked={filterSeverity.low} onCheckedChange={() => handleFilterChange('low')}>Low</DropdownMenuCheckboxItem>
                <DropdownMenuCheckboxItem checked={filterSeverity.medium} onCheckedChange={() => handleFilterChange('medium')}>Medium</DropdownMenuCheckboxItem>
                <DropdownMenuCheckboxItem checked={filterSeverity.high} onCheckedChange={() => handleFilterChange('high')}>High</DropdownMenuCheckboxItem>
              </DropdownMenuContent>
            </DropdownMenu>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Date</TableHead>
                  <TableHead>Route</TableHead>
                  <TableHead className="hidden md:table-cell">Driver</TableHead>
                  <TableHead className="w-full md:w-[40%]">Report Summary</TableHead>
                  <TableHead>Severity</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead><span className="sr-only">Actions</span></TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredIncidents.map((incident) => (
                  <TableRow key={incident.id}>
                    <TableCell>{incident.date}</TableCell>
                    <TableCell className="font-medium">{incident.route}</TableCell>
                    <TableCell className="hidden md:table-cell">{incident.driver}</TableCell>
                    <TableCell className="text-muted-foreground max-w-[200px] sm:max-w-xs truncate">{incident.report}</TableCell>
                    <TableCell>
                      <Badge variant={incident.severity === 'High' ? 'destructive' : incident.severity === 'Medium' ? 'secondary' : 'outline'}
                             className={incident.severity === 'Medium' ? 'bg-orange-400/20 text-orange-600' : ''}>
                        {incident.severity}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <Badge variant="outline">{incident.status}</Badge>
                    </TableCell>
                    <TableCell>
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button aria-haspopup="true" size="icon" variant="ghost">
                            <MoreHorizontal className="h-4 w-4" />
                            <span className="sr-only">Toggle menu</span>
                          </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                          <DropdownMenuLabel>Actions</DropdownMenuLabel>
                          <DropdownMenuItem onSelect={() => handleActionToast('View Details', incident.id)}>View Details</DropdownMenuItem>
                          <DropdownMenuItem onSelect={() => openStatusDialog(incident)}>Update Status</DropdownMenuItem>
                          <DropdownMenuItem onSelect={() => handleActionToast('Escalate', incident.id)}>Escalate</DropdownMenuItem>
                        </DropdownMenuContent>
                      </DropdownMenu>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>
      
      {/* Update Status Dialog */}
      <Dialog open={isStatusDialogOpen} onOpenChange={setIsStatusDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Update Incident Status</DialogTitle>
            <DialogDescription>Change the status for incident {selectedIncident?.id}.</DialogDescription>
          </DialogHeader>
          <form onSubmit={handleUpdateStatus}>
            <div className="grid gap-4 py-4">
               <Select name="status" required defaultValue={selectedIncident?.status}>
                  <SelectTrigger>
                      <SelectValue placeholder="Select a status" />
                  </SelectTrigger>
                  <SelectContent>
                      {incidentStatuses.map(status => (
                          <SelectItem key={status} value={status}>{status}</SelectItem>
                      ))}
                  </SelectContent>
              </Select>
            </div>
            <DialogFooter>
              <Button type="submit">Update Status</Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}
